const https = require('https');

const notionToken = 'YOUR_NOTION_TOKEN';
const parentPageId = 'YOUR_NOTION_PARENT_PAGE_ID';

const claudeText = $json.content[0].text;
const today = new Date();
const dd = String(today.getDate()).padStart(2, '0');
const mm = String(today.getMonth() + 1).padStart(2, '0');
const title = `Atualize Hoje - ${dd}/${mm}`;

const lines = claudeText.split('\n');
const blocks = [];
for (const line of lines) {
  const t = line.trim();
  if (!t) continue;
  if (t === '---') { blocks.push({ object: 'block', type: 'divider', divider: {} }); continue; }
  if (/^\*\*[^*]+\*\*$/.test(t)) {
    blocks.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: [{ type: 'text', text: { content: t.replace(/\*\*/g, '') } }] } });
    continue;
  }
  if (t.startsWith('- ')) {
    blocks.push({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: [{ type: 'text', text: { content: t.substring(2).substring(0, 2000) } }] } });
    continue;
  }
  const isItalic = t.startsWith('_') && t.endsWith('_');
  const cleanText = isItalic ? t.slice(1, -1) : t;
  let remaining = cleanText;
  while (remaining.length > 0) {
    const chunk = remaining.substring(0, 2000);
    remaining = remaining.substring(2000);
    const richText = [{ type: 'text', text: { content: chunk } }];
    if (isItalic) richText[0].annotations = { italic: true };
    blocks.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: richText } });
  }
}

function notionReq(method, path, body) {
  return new Promise((resolve, reject) => {
    const bodyStr = JSON.stringify(body);
    const opts = {
      hostname: 'api.notion.com', port: 443, path, method,
      headers: { 'Authorization': `Bearer ${notionToken}`, 'Content-Type': 'application/json', 'Notion-Version': '2022-06-28', 'Content-Length': Buffer.byteLength(bodyStr) }
    };
    const req = https.request(opts, (res) => {
      let raw = '';
      res.on('data', c => raw += c);
      res.on('end', () => {
        try {
          const parsed = JSON.parse(raw);
          if (res.statusCode < 200 || res.statusCode >= 300) reject(new Error(`Notion ${res.statusCode}: ${JSON.stringify(parsed)}`));
          else resolve(parsed);
        } catch(e) { reject(e); }
      });
    });
    req.on('error', reject);
    req.write(bodyStr);
    req.end();
  });
}

const page = await notionReq('POST', '/v1/pages', {
  parent: { page_id: parentPageId },
  icon: { type: 'emoji', emoji: '📰' },
  properties: { title: [{ text: { content: title } }] },
  children: blocks.slice(0, 100)
});

for (let i = 100; i < blocks.length; i += 100) {
  await notionReq('PATCH', `/v1/blocks/${page.id}/children`, { children: blocks.slice(i, i + 100) });
}

return [{ json: { notion_url: page.url, notion_page_id: page.id, title, status: 'saved' } }];
